import { promises as fs } from "node:fs";
import { execFileSync } from "node:child_process";
import { tmpdir } from "node:os";
import { join, resolve } from "node:path";
import { runBioQueryFromManifest } from "../dist/hosts/run-store.js";
import { nodeProcessRunner } from "../dist/process/node-process-runner.js";

// LITERATE PROGRAMMING (the R/knitr discipline): the README's recorded run is GENERATED by the AGENT RUNNING the
// manifest through the substrate (runBioQueryFromManifest) — not hand-pasted prose that drifts. The substrate's
// run is itself the literate artifact (result.json + receipts.json), so this is just formatting a real run.
// `--check` fails if the committed block is stale; it SKIPS when R/nanoarrow is absent (so no-R CI stays green).
//
//   npm run readme:coloc          # regenerate the block in the README
//   npm run readme:coloc -- --check

const README = resolve("examples/coloc/README.md");
const MANIFEST = resolve("examples/coloc/manifest.json");
const BEGIN = "<!-- BEGIN GENERATED:coloc-run (npm run readme:coloc — do not edit by hand) -->";
const END = "<!-- END GENERATED:coloc-run -->";
const check = process.argv.includes("--check");

const rOk = (() => {
  try { execFileSync("Rscript", ["-e", 'if(!requireNamespace("nanoarrow",quietly=TRUE)) quit(status=1)'], { stdio: "ignore" }); return true; } catch { return false; }
})();

async function block() {
  const cwd = await fs.mkdtemp(join(tmpdir(), "coloc-gen-"));
  const runner = nodeProcessRunner();
  const q = async (sql) => {
    const o = await runBioQueryFromManifest({
      cwd, dbPath: ":memory:", manifestPath: MANIFEST, sql,
      process: { runner }, duckdbInitSql: ["INSTALL nanoarrow FROM community", "LOAD nanoarrow"],
      runId: "g" + Math.random().toString(36).slice(2), now: "T1",
    });
    if (!o.ok) throw new Error(`coloc run failed: ${o.error}`);
    return JSON.parse(await fs.readFile(join(o.runDir, "result.json"), "utf8")).rows;
  };
  const harm = Object.fromEntries((await q("SELECT tissue, count(*) n FROM harmonized GROUP BY tissue")).map((r) => [r.tissue, Number(r.n)]));
  const pp = await q(`SELECT tissue,
      round(max(CASE WHEN hypothesis='PP.H1' THEN posterior END),3) AS H1,
      round(max(CASE WHEN hypothesis='PP.H3' THEN posterior END),3) AS H3,
      round(max(CASE WHEN hypothesis='PP.H4' THEN posterior END),3) AS H4,
      max(engine) AS engine FROM coloc_result GROUP BY tissue ORDER BY H4 DESC`);
  const engine = pp[0]?.engine ?? "?";
  const fix = (n) => Number(n).toFixed(3);
  const note = { Whole_Blood: "COLOCALIZED (shared causal rs6)", Liver: "same locus, DIFFERENT causal (eQTL peak rs3)", Brain: "GWAS signal only (no eQTL)" };
  const lines = pp.map((r) => `  ${String(r.tissue).padEnd(12)} ${fix(r.H1)}   ${fix(r.H3)}   ${fix(r.H4)}   ${String(harm[r.tissue] ?? "?").padStart(3)}    ← ${note[r.tissue] ?? ""}`.trimEnd());
  const top = pp[0]?.tissue;
  return [
    BEGIN,
    `*Generated by \`npm run readme:coloc\` — the agent running the manifest (engine: \`${engine}\`).*`,
    "",
    "```",
    "  tissue       PP.H1   PP.H3   PP.H4   nSNPs",
    ...lines,
    "```",
    "",
    `The colocalizing tissue (top \`PP.H4\`) is **${top}**.`,
    END,
  ].join("\n");
}

const readme = await fs.readFile(README, "utf8");
const re = new RegExp(`${BEGIN.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}[\\s\\S]*?${END.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}`);
if (!re.test(readme)) { console.error(`generate-coloc-readme: markers not found in ${README}`); process.exit(1); }

if (!rOk) {
  console.log(`generate-coloc-readme: ${check ? "check skipped" : "skipped"} — R 'nanoarrow' not available`);
  process.exit(0);
}

const fresh = await block();
const updated = readme.replace(re, fresh);
if (check) {
  if (updated !== readme) { console.error("generate-coloc-readme: README coloc-run block is STALE — run `npm run readme:coloc`"); process.exit(1); }
  console.log("generate-coloc-readme: coloc-run block is current");
} else {
  await fs.writeFile(README, updated);
  console.log("generate-coloc-readme: regenerated the coloc-run block");
}
